import getRegistry from './services/registry';
import async from 'async';
import NotificationsService from './services/NotificationsService';

module.exports = {

    NotificationsService: NotificationsService,

    init(cb){
        let notificationsService;

        // Initialize all the services.
        // TODO: This is done in serial order for now, but should be moved to be more parallel
        // when there are more services support in the background service than the notifications
        // API
        async.waterfall([

            // Fetch the registry entries
            (next) => {
                getRegistry(next);
            },

            // Store the registry entries for later
            (services, next) => {
                // Convert the returned registry payload into a lookup table from service name to the service
                // base url
                services.forEach( (service) => {
                    if(service.name === 'notifications'){
                        notificationsService = service;
                    }
                });
                next();
            },

            // Initialize the Notifications API
            (next) => {
                this.notifications = new NotificationsService();

                this.notifications.init(notificationsService, next);
            }

        ], function(err) {
            cb(err);
        });
    }
};
